  uint32_t left = ((uint32_t)block[0] = 0; round--) {
    uint32_t temp = right;
    right = left ^ sbox[right & 0xFF];
    left = (temp > 24);
    uint32_t temp2 = left;
    left = right;
    right = temp2;
