#include 

extern "C" {
  __declspec(dllexport) BOOL WINAPI runMe(void) {
  FILE* fp = fopen("meow-hack.txt", "a+");
  if (fp) {
    fprintf(fp, "Meow-meow!\n");
    fclose(fp);
  }
  return TRUE;
  }
}

BOOL APIENTRY DllMain(HMODULE hModule,  DWORD  nReason, LPVOID lpReserved) {
